"use client";

import { useEffect, useRef, useState } from "react";

const BACKEND_URL =
  process.env.NEXT_PUBLIC_VOICE_BACKEND_URL || "http://localhost:8001";

type Message = {
  from: "user" | "assistant";
  text: string;
};

type Domain = "restaurant" | "ecommerce" | "car_booking";

export default function VoiceAssistant() {
  const [sessionId, setSessionId] = useState<string | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");
  const [recording, setRecording] = useState(false);
  const [domain, setDomain] = useState<Domain>("restaurant");

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<BlobPart[]>([]);

  // Session UUID stored in localStorage
  useEffect(() => {
    if (typeof window === "undefined") return;
    let id = window.localStorage.getItem("aurora_voice_session");
    if (!id) {
      id = crypto.randomUUID();
      window.localStorage.setItem("aurora_voice_session", id);
    }
    setSessionId(id);
  }, []);

  const pushMsg = (msg: Message) =>
    setMessages((prev) => [...prev, msg]);

  // Call /query
  const sendTextToBackend = async (text: string) => {
    if (!sessionId) return;
    pushMsg({ from: "user", text });

    try {
      const res = await fetch(`${BACKEND_URL}/query`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          text,
          user_id: sessionId,
          domain,
        }),
      });

      if (!res.ok) {
        throw new Error(await res.text());
      }

      const data: { response: string } = await res.json();
      pushMsg({ from: "assistant", text: data.response });
    } catch (err) {
      console.error(err);
      pushMsg({
        from: "assistant",
        text: "Sorry, something went wrong talking to the voice backend.",
      });
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const trimmed = input.trim();
    if (!trimmed) return;
    setInput("");
    await sendTextToBackend(trimmed);
  };

  // Mic recording helpers
  const startRecording = async () => {
    if (recording) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mr = new MediaRecorder(stream);
      audioChunksRef.current = [];

      mr.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mr.onstop = async () => {
        const blob = new Blob(audioChunksRef.current, { type: "audio/webm" });
        audioChunksRef.current = [];

        const formData = new FormData();
        formData.append("file", blob, "chunk.webm");

        try {
          const res = await fetch(`${BACKEND_URL}/stt`, {
            method: "POST",
            body: formData,
          });
          if (!res.ok) {
            throw new Error(await res.text());
          }
          const data: { text: string } = await res.json();
          const transcript = (data.text || "").trim();
          if (transcript) {
            await sendTextToBackend(transcript);
          } else {
            pushMsg({
              from: "assistant",
              text: "I couldn't hear that clearly. Please try again.",
            });
          }
        } catch (err) {
          console.error(err);
          pushMsg({
            from: "assistant",
            text: "Speech recognition failed. Please try again.",
          });
        }

        stream.getTracks().forEach((t) => t.stop());
        setRecording(false);
      };

      mediaRecorderRef.current = mr;
      mr.start();
      setRecording(true);
      pushMsg({
        from: "assistant",
        text: "Listening… speak now.",
      });
    } catch (err) {
      console.error(err);
      pushMsg({
        from: "assistant",
        text: "Could not access microphone. Please check permissions.",
      });
    }
  };

  const stopRecording = () => {
    if (!recording || !mediaRecorderRef.current) return;
    mediaRecorderRef.current.stop();
  };

  return (
    <div className="surface rounded-xl p-4 md:p-6 space-y-4">
      <div className="flex items-center justify-between gap-3">
        <div>
          <p className="text-xs tracking-[0.2em] uppercase text-muted mb-1">
            Voice Assistant
          </p>
          <p className="font-serif text-lg text-warm-white">
            Aurora Dining Concierge
          </p>
        </div>
        <div className="flex items-center gap-2 text-xs">
          <label className="text-muted">Domain:</label>
          <select
            className="bg-transparent border border-gold/40 text-warm-white text-xs px-2 py-1 rounded"
            value={domain}
            onChange={(e) =>
              setDomain(e.target.value as Domain)
            }
          >
            <option value="restaurant">Restaurant</option>
            <option value="ecommerce">E‑commerce</option>
            <option value="car_booking">Car booking</option>
          </select>
        </div>
      </div>

      <div className="h-52 md:h-64 overflow-y-auto space-y-2 border border-gold/10 rounded-lg p-3 bg-charcoal-light/40">
        {messages.length === 0 && (
          <p className="text-xs text-muted">
            Start by speaking or typing a request, for example:
            “Book a table for 4 tomorrow dinner”.
          </p>
        )}
        {messages.map((m, idx) => (
          <div
            key={idx}
            className={`flex ${
              m.from === "user" ? "justify-end" : "justify-start"
            }`}
          >
            <div
              className={`px-3 py-2 rounded-lg text-xs md:text-sm max-w-[85%] ${
                m.from === "user"
                  ? "bg-gold/15 text-warm-white"
                  : "bg-charcoal-light text-warm-white"
              }`}
            >
              {m.text}
            </div>
          </div>
        ))}
      </div>

      <div className="flex flex-col md:flex-row items-center gap-3">
        <button
          type="button"
          onClick={recording ? stopRecording : startRecording}
          className={`px-4 py-2 rounded-full text-xs tracking-[0.15em] uppercase ${
            recording
              ? "bg-red-600 text-white"
              : "border border-gold/60 text-gold hover:bg-gold hover:text-charcoal-deep transition"
          }`}
        >
          {recording ? "Stop Recording" : "Hold to Speak"}
        </button>
        <form onSubmit={handleSubmit} className="flex-1 flex gap-2 w-full">
          <input
            className="flex-1 bg-transparent border border-gold/30 rounded-full px-3 py-2 text-xs md:text-sm text-warm-white"
            placeholder="Or type your request here…"
            value={input}
            onChange={(e) => setInput(e.target.value)}
          />
          <button
            type="submit"
            className="px-4 py-2 rounded-full bg-gold text-charcoal-deep text-xs tracking-[0.15em] uppercase"
          >
            Send
          </button>
        </form>
      </div>
    </div>
  );
}

